// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {

	var msgDependantsNeeded = 'This Task is dependent on the completion of its Subtasks but Subtasks have not been created yet. Please create dependent subtasks.';


	// 2.5.13:  08.10.20  | KT | SEQ | STRY0076607:  SEQ - Task Form – WAITING State – Flag passes from Parent Task to Subtask
	if(newValue == 'true'){
		//g_form.addErrorMessage(msgDependantsNeeded);
		g_form.showFieldMsg('u_wait_for_subtasks_to_finish', msgDependantsNeeded, 'error', false);
		g_form.showFieldMsg('u_wait_for_subtasks_to_finish', 'This Task is dependent on the completion of its Subtasks and it will not be marked as Unassigned or Assigned until all Subtasks have been Completed, Canceled, or Closed Incomplete.','info');

		if (g_form.getDisplayValue('tasker_type') == 'Approval with signature' || (g_form.getDisplayValue('tasker_type') == 'Approval without signature') && 1) {

			if (g_scratchpad.numApprovalSubTasks >= 1){
				g_form.showFieldMsg('u_wait_for_subtasks_to_finish', 'This Task is an "Approval" Task Type and it has a Subtask with an "Approval" Task Type. If the "Approval" Subtask is Rejected, then this task will also be rejected.','info');
			}
		}
	} else if (!isLoading && newValue == 'false'){
		g_form.showFieldMsg('u_wait_for_subtasks_to_finish', 'This Task is no longer dependent on the completion of its Subtasks.','info');
	}

}
